  `length` decimal(10, 2) NULL DEFAULT NULL COMMENT '长(mm)',
  `width` decimal(10, 2) NULL DEFAULT NULL COMMENT '宽(mm)',
  `material_qty` int NULL DEFAULT NULL COMMENT '材料数量',
